sql:
SELECT COUNT(*) AS report_count
FROM analyst_reports
WHERE stock_id = 1;

SELECT COUNT(*) AS split_count
FROM stock_splits
WHERE split_date LIKE '2020-%';

SELECT industry_name
FROM industry
WHERE parent_industry_id IS NULL;

external_knowledge:
* 'Top-performing stocks' refers to those with the highest average closing prices over the specified period; 
* 'Average closing prices' are calculated based on the closing prices of stocks over the last year;
* 'Sentiment of the latest news articles' indicates whether the most recent news about each stock is positive, negative, or neutral.

sql:
SELECT MAX(report_date) AS latest_report_date
FROM analyst_reports
WHERE stock_id = 0;
